const msg = $input.first().json.body?.message ?? {};
const toolCalls = msg.toolCalls ?? [];
const call = msg.call ?? {};
const vars = call?.assistantOverrides?.variableValues ?? {};
const phone = call?.customer?.number ?? null;

// SIP-Headers normalisieren (case-insensitive). Vapi stellt sie je nach
// Version unter call.customer.sipHeaders oder call.sipHeaders bereit.
const rawSip = call?.customer?.sipHeaders ?? call?.sipHeaders ?? {};
const sip = {};
for (const [k, v] of Object.entries(rawSip)) {
  if (typeof v === 'string') sip[k.toLowerCase()] = v;
}

const first = toolCalls[0]?.function ?? {};
const toolName = first.name ?? null;
const toolArgs = first.arguments ?? {};

return [{
  json: {
    tool_name: toolName,
    tool_args: toolArgs,
    tool_call_id: toolCalls[0]?.id ?? null,
    phone,
    // Priorität: variableValues → SIP-Header → toolArgs
    sales_lead_id:    vars.sales_lead_id    ?? sip['x-sales-lead-id']    ?? toolArgs.sales_lead_id    ?? null,
    sales_call_id:    vars.sales_call_id    ?? sip['x-sales-call-id']    ?? null,
    sales_program_id: vars.sales_program_id ?? sip['x-sales-program-id'] ?? toolArgs.sales_program_id ?? null
  }
}];

const extracted = $('Extract Tool & Args').first().json;
const raw = $input.first().json;
let rows = [];
if (Array.isArray(raw)) rows = raw;
else if (Array.isArray(raw && raw.body)) rows = raw.body;
else if (raw && typeof raw === 'object' && raw.id) rows = [raw];
const lead = rows[0] || null;
const program = lead && lead.program ? lead.program : null;

// Aktivsten Sales-Call bestimmen: bevorzugt 'in_progress' > 'initiated' > 'ringing',
// sonst jüngsten beliebigen Call. recent_calls ist bereits DESC sortiert (neueste zuerst).
const recent = (lead && Array.isArray(lead.recent_calls)) ? lead.recent_calls : [];
const priority = ['in_progress', 'ringing', 'initiated'];
let activeCall = null;
for (const p of priority) {
  activeCall = recent.find(c => c && c.status === p) || null;
  if (activeCall) break;
}
if (!activeCall && recent.length > 0) activeCall = recent[0];

return [{
  json: {
    tool_name: extracted.tool_name,
    tool_args: extracted.tool_args,
    tool_call_id: extracted.tool_call_id,
    sales_lead_id: (lead && lead.id) || extracted.sales_lead_id,
    sales_program_id: (program && program.id) || extracted.sales_program_id,
    sales_call_id: extracted.sales_call_id || (activeCall && activeCall.id) || null,
    phone: extracted.phone,
    lead: lead,
    program: program
  }
}];
